"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { useToast } from "@/hooks/use-toast";

type Step = 1 | 2 | 3 | 4;

const goals = [
  { id: "reduce-stress", label: "Reduce Daily Stress", icon: "🌬" },
  { id: "better-sleep", label: "Improve Sleep Quality", icon: "🌙" },
  { id: "emotional", label: "Emotional Awareness", icon: "🧠" },
  { id: "productivity", label: "Boost Productivity", icon: "☀️" },
  { id: "positivity", label: "Cultivate Positivity", icon: "😊" },
  { id: "mindfulness", label: "Build Mindfulness", icon: "🌿" },
];

const schedules = [
  { id: "morning", label: "Morning", time: "8:00 AM", icon: "☀️" },
  { id: "afternoon", label: "Afternoon", time: "1:00 PM", icon: "✦" },
  { id: "evening", label: "Evening", time: "8:00 PM", icon: "🌙" },
];

const stepMeta = [
  { label: "Name" },
  { label: "Goals" },
  { label: "Schedule" },
  { label: "Launch" },
];

function CheckIcon({ color = "currentColor", size = 16 }: { color?: string; size?: number }) {
  return (
    <svg width={size} height={size} viewBox="0 0 16 16" fill="none">
      <path
        d="M3 8.5L6.5 12 13 5"
        stroke={color}
        strokeWidth="1.6"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function ArrowRight() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M3 8h10M9 4l4 4-4 4"
        stroke="#fff"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function StepIcon({ step, active }: { step: number; active: boolean }) {
  const color = active ? "#16a34a" : "rgba(255,255,255,0.3)";
  if (step === 1)
    return (
      <svg width="15" height="15" viewBox="0 0 16 16" fill="none">
        <path
          d="M8 2a3 3 0 1 1 0 6 3 3 0 0 1 0-6zM3 13c0-2.8 2.2-4 5-4s5 1.2 5 4"
          stroke={color}
          strokeWidth="1.4"
          strokeLinecap="round"
        />
      </svg>
    );
  if (step === 2)
    return (
      <svg width="15" height="15" viewBox="0 0 16 16" fill="none">
        <circle cx="8" cy="8" r="5.5" stroke={color} strokeWidth="1.4" />
        <path d="M5.5 8l2 2 3-3" stroke={color} strokeWidth="1.4" strokeLinecap="round" />
      </svg>
    );
  if (step === 3)
    return (
      <svg width="15" height="15" viewBox="0 0 16 16" fill="none">
        <circle cx="8" cy="8" r="5.5" stroke={color} strokeWidth="1.4" />
        <path d="M8 5.5v2.5l1.5 1.5" stroke={color} strokeWidth="1.4" strokeLinecap="round" />
      </svg>
    );
  return (
    <svg width="15" height="15" viewBox="0 0 16 16" fill="none">
      <path
        d="M3 8.5L6.5 12 13 5"
        stroke={color}
        strokeWidth="1.4"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function StepIndicator({ current }: { current: Step }) {
  return (
    <div className="flex items-center justify-center mb-8">
      {stepMeta.map((s, i) => {
        const stepNum = (i + 1) as Step;
        const isDone = current > stepNum;
        const isActive = current === stepNum;

        return (
          <div key={i} className="flex items-center">
            <div className="relative flex flex-col items-center">
              {/* Circle */}
              <div
                className="relative w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300"
                style={{
                  background: isDone
                    ? "#16a34a"
                    : isActive
                    ? "#fff"
                    : "rgba(255,255,255,0.05)",
                  border: isDone
                    ? "1.5px solid #16a34a"
                    : isActive
                    ? "1.5px solid #4ade80"
                    : "1.5px solid rgba(255,255,255,0.12)",
                  boxShadow: isActive ? "0 0 0 4px rgba(74,222,128,0.18)" : "none",
                }}
              >
                {/* Pulse ring for active */}
                {isActive && (
                  <span
                    className="absolute inset-0 rounded-full border border-green-400 pointer-events-none"
                    style={{ animation: "pulse-ring 1.8s ease-out infinite" }}
                  />
                )}
                {isDone ? (
                  <CheckIcon color="#fff" size={15} />
                ) : (
                  <StepIcon step={stepNum} active={isActive} />
                )}
              </div>

              {/* Label */}
              <span
                className="absolute mt-11 text-[10px] font-medium tracking-widest uppercase whitespace-nowrap hidden md:block"
                style={{
                  color: isActive
                    ? "#4ade80"
                    : isDone
                    ? "#16a34a"
                    : "rgba(255,255,255,0.2)",
                }}
              >
                {s.label}
              </span>
            </div>

            {/* Connector line */}
            {i < stepMeta.length - 1 && (
              <div
                className="relative mx-1 h-0.5 w-11 overflow-hidden"
                style={{ background: "rgba(255,255,255,0.08)" }}
              >
                <div
                  className="absolute inset-y-0 left-0 bg-green-500 transition-all duration-500"
                  style={{ width: isDone ? "100%" : "0%" }}
                />
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

export default function OnboardingPage() {
  const [step, setStep] = useState<Step>(1);
  const [name, setName] = useState("");
  const [selectedGoals, setSelectedGoals] = useState<Set<string>>(new Set());
  const [schedule, setSchedule] = useState("afternoon");
  const [done, setDone] = useState(false);
  const router = useRouter();
  const { toast } = useToast();

  const goStep = (n: Step) => setStep(n);

  const toggleGoal = (id: string) => {
    setSelectedGoals((prev) => {
      const next = new Set(prev);
      next.has(id) ? next.delete(id) : next.add(id);
      return next;
    });
  };

  const finish = () => {
    setDone(true);
    toast({
      title: "All set! 🌿",
      description: "Welcome to your personalized wellness space.",
    });
    setTimeout(() => router.push("/app"), 1200);
  };

  return (
    <>
      <style>{`
        @keyframes pulse-ring {
          0%   { transform: scale(1); opacity: 0.6; }
          100% { transform: scale(1.55); opacity: 0; }
        }
        @keyframes fadeUp {
          from { opacity: 0; transform: translateY(10px); }
          to   { opacity: 1; transform: translateY(0); }
        }
        .panel-enter { animation: fadeUp 0.28s ease; }
      `}</style>

      <div
        className="min-h-screen flex items-center justify-center p-4 relative overflow-hidden"
        style={{
          background:
            "radial-gradient(ellipse 90% 60% at 50% 0%, rgba(74,222,128,0.09) 0%, transparent 65%), linear-gradient(160deg, #0a0f0a 0%, #0c1a0e 50%, #090c12 100%)",
        }}
      >
        {/* Ambient blobs */}
        <div
          className="pointer-events-none absolute -top-32 -left-32 w-96 h-96 rounded-full"
          style={{
            background:
              "radial-gradient(circle, rgba(74,222,128,0.25) 0%, transparent 70%)",
            filter: "blur(70px)",
            opacity: 0.15,
          }}
        />
        <div
          className="pointer-events-none absolute bottom-0 right-0 w-80 h-80 rounded-full"
          style={{
            background:
              "radial-gradient(circle, rgba(56,189,248,0.5) 0%, transparent 70%)",
            filter: "blur(80px)",
            opacity: 0.08,
          }}
        />

        <div className="w-full max-w-md relative">
          <StepIndicator current={step} />

          {/* Card */}
          <div
            className="relative rounded-3xl overflow-hidden"
            style={{
              background: "rgba(255,255,255,0.04)",
              border: "1px solid rgba(255,255,255,0.08)",
              backdropFilter: "blur(24px)",
              boxShadow:
                "0 0 0 1px rgba(74,222,128,0.06), 0 32px 64px rgba(0,0,0,0.5)",
            }}
          >
            {/* Top progress line */}
            <div
              className="absolute top-0 left-0 h-0.5 transition-all duration-500"
              style={{
                width: `${(step / 4) * 100}%`,
                background:
                  "linear-gradient(90deg, transparent, #4ade80, transparent)",
              }}
            />

            <div className="p-8">
              {/* ── STEP 1 ── */}
              {step === 1 && (
                <div className="panel-enter space-y-6">
                  <div className="text-center">
                    <div
                      className="w-12 h-12 rounded-2xl flex items-center justify-center mx-auto mb-5 text-xl"
                      style={{
                        background: "rgba(74,222,128,0.1)",
                        border: "1px solid rgba(74,222,128,0.2)",
                      }}
                    >
                      ✦
                    </div>
                    <h2
                      className="text-2xl font-semibold text-white mb-1"
                      style={{ letterSpacing: "-0.02em" }}
                    >
                      What's your name?
                    </h2>
                    <p
                      className="text-sm"
                      style={{ color: "rgba(255,255,255,0.42)", lineHeight: 1.6 }}
                    >
                      We'd love to know what to call you.
                    </p>
                  </div>

                  <div>
                    <label
                      className="block text-[10px] font-medium uppercase tracking-widest mb-2"
                      style={{ color: "rgba(255,255,255,0.38)" }}
                    >
                      Your Name
                    </label>
                    <input
                      type="text"
                      placeholder="e.g. Alex"
                      value={name}
                      autoComplete="off"
                      onChange={(e) => setName(e.target.value)}
                      onKeyDown={(e) =>
                        e.key === "Enter" && name.trim() && goStep(2)
                      }
                      className="w-full h-12 rounded-2xl px-4 text-white text-base outline-none transition-all"
                      style={{
                        background: "rgba(255,255,255,0.06)",
                        border: "1px solid rgba(255,255,255,0.1)",
                        fontFamily: "inherit",
                      }}
                    />
                  </div>

                  <button
                    onClick={() => goStep(2)}
                    disabled={!name.trim()}
                    className="w-full h-12 rounded-2xl font-medium text-sm flex items-center justify-center gap-2 text-white transition-all disabled:opacity-30 disabled:cursor-not-allowed hover:-translate-y-px"
                    style={{
                      background: "linear-gradient(135deg, #16a34a, #22c55e)",
                      boxShadow: name.trim()
                        ? "0 8px 24px rgba(22,163,74,0.3)"
                        : "none",
                    }}
                  >
                    Continue <ArrowRight />
                  </button>
                </div>
              )}

              {/* ── STEP 2 ── */}
              {step === 2 && (
                <div className="panel-enter space-y-5">
                  <div className="text-center">
                    <h2
                      className="text-2xl font-semibold text-white mb-1"
                      style={{ letterSpacing: "-0.02em" }}
                    >
                      Hey {name}! 🌿
                    </h2>
                    <p
                      className="text-sm"
                      style={{ color: "rgba(255,255,255,0.42)" }}
                    >
                      Pick your main wellness goals.
                    </p>
                  </div>

                  <div className="grid grid-cols-2 gap-2">
                    {goals.map((g) => {
                      const sel = selectedGoals.has(g.id);
                      return (
                        <button
                          key={g.id}
                          onClick={() => toggleGoal(g.id)}
                          className="relative p-3 rounded-2xl text-left transition-all"
                          style={{
                            background: sel
                              ? "rgba(74,222,128,0.1)"
                              : "rgba(255,255,255,0.04)",
                            border: sel
                              ? "1px solid rgba(74,222,128,0.4)"
                              : "1px solid rgba(255,255,255,0.08)",
                          }}
                        >
                          {sel && (
                            <span className="absolute top-2 right-2 w-4 h-4 rounded-full bg-green-500 flex items-center justify-center">
                              <CheckIcon color="#fff" size={10} />
                            </span>
                          )}
                          <span className="block text-base mb-1">{g.icon}</span>
                          <span
                            className="text-[11px] font-medium leading-snug block"
                            style={{
                              color: sel
                                ? "#86efac"
                                : "rgba(255,255,255,0.5)",
                            }}
                          >
                            {g.label}
                          </span>
                        </button>
                      );
                    })}
                  </div>

                  <button
                    onClick={() => goStep(3)}
                    disabled={selectedGoals.size === 0}
                    className="w-full h-12 rounded-2xl font-medium text-sm flex items-center justify-center gap-2 text-white transition-all disabled:opacity-30 disabled:cursor-not-allowed hover:-translate-y-px"
                    style={{
                      background: "linear-gradient(135deg, #16a34a, #22c55e)",
                      boxShadow:
                        selectedGoals.size > 0
                          ? "0 8px 24px rgba(22,163,74,0.3)"
                          : "none",
                    }}
                  >
                    Next Step <ArrowRight />
                  </button>
                </div>
              )}

              {/* ── STEP 3 ── */}
              {step === 3 && (
                <div className="panel-enter space-y-5">
                  <div className="text-center">
                    <h2
                      className="text-2xl font-semibold text-white mb-1"
                      style={{ letterSpacing: "-0.02em" }}
                    >
                      Daily Check-ins
                    </h2>
                    <p
                      className="text-sm"
                      style={{ color: "rgba(255,255,255,0.42)" }}
                    >
                      When would you like to log your mood?
                    </p>
                  </div>

                  <div className="flex flex-col gap-2">
                    {schedules.map((s) => {
                      const sel = schedule === s.id;
                      return (
                        <button
                          key={s.id}
                          onClick={() => setSchedule(s.id)}
                          className="flex items-center justify-between px-4 py-3 rounded-2xl transition-all"
                          style={{
                            background: sel
                              ? "rgba(74,222,128,0.07)"
                              : "rgba(255,255,255,0.04)",
                            border: sel
                              ? "1px solid rgba(74,222,128,0.35)"
                              : "1px solid rgba(255,255,255,0.08)",
                          }}
                        >
                          <div className="flex items-center gap-3">
                            <div
                              className="w-9 h-9 rounded-xl flex items-center justify-center text-base transition-all"
                              style={{
                                background: sel
                                  ? "rgba(74,222,128,0.15)"
                                  : "rgba(255,255,255,0.05)",
                              }}
                            >
                              {s.icon}
                            </div>
                            <div className="text-left">
                              <p
                                className="text-sm font-medium"
                                style={{
                                  color: sel ? "#fff" : "rgba(255,255,255,0.7)",
                                }}
                              >
                                {s.label}
                              </p>
                              <p
                                className="text-xs"
                                style={{ color: "rgba(255,255,255,0.3)" }}
                              >
                                {s.time}
                              </p>
                            </div>
                          </div>
                          {/* Radio dot */}
                          <div
                            className="w-4 h-4 rounded-full relative flex items-center justify-center transition-all"
                            style={{
                              border: sel
                                ? "1.5px solid #22c55e"
                                : "1.5px solid rgba(255,255,255,0.2)",
                              background: sel ? "#22c55e" : "transparent",
                            }}
                          >
                            {sel && (
                              <div className="w-1.5 h-1.5 rounded-full bg-white" />
                            )}
                          </div>
                        </button>
                      );
                    })}
                  </div>

                  <button
                    onClick={() => goStep(4)}
                    className="w-full h-12 rounded-2xl font-medium text-sm flex items-center justify-center gap-2 text-white hover:-translate-y-px transition-all"
                    style={{
                      background: "linear-gradient(135deg, #16a34a, #22c55e)",
                      boxShadow: "0 8px 24px rgba(22,163,74,0.3)",
                    }}
                  >
                    Almost there <ArrowRight />
                  </button>
                </div>
              )}

              {/* ── STEP 4 ── */}
              {step === 4 && (
                <div className="panel-enter space-y-6 text-center">
                  <div>
                    <div
                      className="w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-5 text-3xl"
                      style={{
                        background:
                          "radial-gradient(circle, rgba(74,222,128,0.18) 0%, rgba(74,222,128,0.04) 100%)",
                        border: "1px solid rgba(74,222,128,0.28)",
                        boxShadow: "0 0 40px rgba(74,222,128,0.15)",
                      }}
                    >
                      💚
                    </div>
                    <h2
                      className="text-2xl font-semibold text-white mb-1"
                      style={{ letterSpacing: "-0.02em" }}
                    >
                      You're all set!
                    </h2>
                    <p
                      className="text-sm px-4"
                      style={{ color: "rgba(255,255,255,0.42)", lineHeight: 1.6 }}
                    >
                      Your dashboard is ready. Your wellness journey starts now.
                    </p>
                  </div>

                  <div
                    className="p-4 rounded-2xl text-left"
                    style={{
                      background: "rgba(74,222,128,0.05)",
                      border: "1px solid rgba(74,222,128,0.12)",
                    }}
                  >
                    <p
                      className="text-xs italic"
                      style={{ color: "rgba(134,239,172,0.65)", lineHeight: 1.6 }}
                    >
                      "Each step you take is a win for your future self."
                    </p>
                  </div>

                  <button
                    onClick={finish}
                    disabled={done}
                    className="w-full h-12 rounded-2xl font-medium text-sm flex items-center justify-center gap-2 text-white transition-all hover:scale-[1.02] active:scale-[0.98] disabled:opacity-60"
                    style={{
                      background:
                        "linear-gradient(135deg, #15803d, #22c55e, #4ade80)",
                      boxShadow:
                        "0 12px 32px rgba(22,163,74,0.4), 0 0 0 1px rgba(74,222,128,0.2)",
                    }}
                  >
                    Get Started
                    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                      <path
                        d="M2 8h9M8 5l3 3-3 3"
                        stroke="#fff"
                        strokeWidth="1.5"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      />
                    </svg>
                  </button>
                </div>
              )}
            </div>
          </div>

          {/* Step count hint */}
          <p
            className="text-center text-[10px] font-medium uppercase tracking-widest mt-4"
            style={{ color: "rgba(255,255,255,0.18)" }}
          >
            Step {step} of 4
          </p>
        </div>
      </div>
    </>
  );
}
